var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"으갸야약……!! 사람 살려……!!","JPN":"ぎゃあああ……！！　助けて……！！","ENG":"Aaaaagh...! Somebody help me...!","TWN":"呀呀呀……！救命啊……！！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"수리야 님! 이렇게까지 깊게 들어온다는 이야기는 없었잖아요!!","JPN":"スーリヤさん！　こんな奥まで入るなんて聞いてませんよ！！","ENG":"Surya! You never said we'd be going this deep into the danger zone!","TWN":"蘇莉耶！不是說好不會下到這麼深的嗎！！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그리고 대체 이 사람 같이 생긴 고철 덩어리는 다 뭔가요! 좀비처럼 계속 따라오는데요!?","JPN":"あと、この人の形をした鉄くずは何ですか？　ゾンビみたいに延々とついてくるんですけど！？","ENG":"And what's with all these scrap heaps that look like people? They're following us like zombies!","TWN":"還有，這個長得像人的廢鐵塊到底是什麼啊！像僵屍一樣一直跟著我！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"으아아아!! 가이드고 나발이고, 이러다간 다 죽는다고요……!!","JPN":"わあああ！！　ガイドどころじゃないよもー！　このままだとみんな死んでしまいます……！！","ENG":"Aaah!! Guide or not, we're all gonna die at this rate...!","TWN":"啊啊啊！！什麼指南不指南的，這樣下去我們都會死的……！！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"그러니까 말했을 텐데, 아샤. 이건 평범한 투어가 아니라고.","JPN":"だから言っただろう、アーシャ。これは普通のツアーではないと。","ENG":"I told you, Asha. This isn't just some regular tour.","TWN":"所以我說過了，阿莎。這不是普通的旅行。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"이번 건은 구 관리국과 관련된 문제니까, 너는 길만 알려주고 빠지라고 하지 않았나?","JPN":"今回の件は旧管理局がらみだから、君は道だけ教えて帰れと言ったはずだ。","ENG":"This one involves the Old Administration, remember? I said you should just give directions and stay out of it.","TWN":"這次的事情與舊管理局有關，不是讓你指路後就離開嗎？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이 정도일 줄은 몰랐다고요! 애초에 로터스에 위험하지 않은 곳이 어디 있다고!","JPN":"こんは大変だなんて知らなかったんです！　そもそもロータスなんてどこへ行っても危ないのは同じですし！","ENG":"I didn't know it'd be this bad! Honestly, is there anywhere in Lotus that isn't dangerous?!","TWN":"沒想到會這樣！一開始就沒有洛德斯的安全之地！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"게다가 수리야 님, 어차피 길치라서 여기 지리를 하나도 모르시잖아요!","JPN":"それにスーリヤさん方向音痴だから、この辺の地理は全くわからないじゃないですか！","ENG":"Besides, Surya, you're terrible with directions! You don't even know the area!","TWN":"而且蘇莉耶，反正你是路癡，對這裡的地理一點都不熟悉吧！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아닐라 님이라면 모를까, 수리야 님 혼자서는 가이드 자체가 성립되지 않는다고요!","JPN":"アニラさんならともかく、スーリヤさん1人だとガイドできないに決まってます！","ENG":"If it were Anila, maybe. But there's no way this tour would work with just you.","TWN":"如果是雅妮拉還好說，但蘇莉耶一個人是無法當這個導遊的！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"크흠, 아직 지도를 다 못 외웠을 뿐이다.","JPN":"ごほん、まだ地図を覚えられていないだけだ。","ENG":"Ahem... I just haven't finished memorizing the map, that's all.","TWN":"咳咳，我只是還沒完全記住地圖而已。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아샤! 정말로 이 길이 맞아?","JPN":"アーシャ！　本当にこの道で合ってる？","ENG":"Asha, are you sure this is the right path?","TWN":"阿莎！這條路真的對嗎？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"왠지 아까부터 똑같은 곳을 뺑뺑 돌고 있는 것 같은데?","JPN":"なんか、さっきから同じ場所をぐるぐる回ってる気がするんだけど。","ENG":"It feels like we've been going in circles for a while now...","TWN":"總覺得從剛才開始一直在同一個地方轉圈呢？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"거, 걱정하지 마, 미나야!","JPN":"だ、大丈夫よ、ミナ！","ENG":"D-don't worry, Mina!","TWN":"別，別擔心，米娜！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그래도 이곳 지형은 사전에 충분히 조사해 두었으니까!","JPN":"ここの地形は事前にちゃんと調べてあるから！","ENG":"I did my homework and studied the terrain in advance!","TWN":"不過這裡的地形已經事先充分調查過了！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"무엇보다도…….","JPN":"何より……","ENG":"And more importantly...","TWN":"最重要的是……"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"우리 바루나 투어는 클라이언트를 실망시키지 않는 게 모토거든……!","JPN":"うちのヴァルナツアーはクライアントをがっかりさせないのがモットーだから……！","ENG":"At Varuna Tour, we never let a client down. That's our motto.","TWN":"我們伐樓拿旅行社的宗旨就是不讓客戶失望……！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"갑자기 뭐야?","JPN":"急に何？","ENG":"What the?","TWN":"……突然怎麼回事？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"땅 밑에서…? 이건 지진인가……?","JPN":"地面の下から……？　地震……？","ENG":"From underground...? Was that an earthquake...?","TWN":"地下……？這是地震嗎……？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"미나야, 거기 가만히 있지 말고 얼른 뛰어……!","JPN":"ミナ、そこに突っ立ってないで早く走って……！","ENG":"Mina, don't just stand there... Run!","TWN":"米娜，別站在那裡，快跑……！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"휘말린다고!","JPN":"巻き込まれるわ！","ENG":"You'll get caught in it!","TWN":"被捲進去了！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"휘말려……?","JPN":"巻き込まれる……？","ENG":"Caught in it...?","TWN":"被捲入……？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"좋아, 수리야 님! 바로 지금이에요!","JPN":"よし、スーリヤさん！　今です！","ENG":"Now, Surya! This is the moment!","TWN":"好，蘇莉耶！就是現在！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};